import 'lodash/merge';
import 'react';
import styled from 'styled-components';
import '../../design-system/css-configs/components/index.js';
import '../../design-system/types/Size.js';
import '../../design-system/types/ThemeKey.js';
import '../../design-system/theme/themes/config.js';
import '../../design-system/theme/themes/dark/index.js';
import '../../design-system/theme/themes/light/index.js';
import { SPACES } from '../../design-system/theme/themes/variables.js';
import { getFromProps } from '../../helpers/getFromProps.js';

const fromProps = getFromProps();
const TextWrapper = styled.span ``;
const IconWrapper = styled.span `
  vertical-align: text-top;
`;
const StyledLink = styled.a.withConfig({
    shouldForwardProp: prop => !['cssConfig'].includes(prop)
}) `
  text-decoration: none;

  font-family: ${fromProps('fontFamily')};
  font-size: ${fromProps('fontSize')};
  line-height: ${fromProps('lineHeight')};
  font-style: ${fromProps('fontStyle')};
  font-weight: ${fromProps('fontWeight')};
  
  &, &:not(.kl-components-link_visited):visited {
    color: ${fromProps('enabled.color')};

    outline: none;
    border: none;
  }

  &&:focus-visible {
    box-shadow: ${fromProps('focus.boxShadow')};
    outline: none;
    border-radius: ${fromProps('borderRadius')};
  }

  &&:hover {
    color: ${fromProps('hover.color')};
  }

  &&:active {
    color: ${fromProps('active.color')};
  }

  &&.kl-components-link_visited:visited {
    color: ${fromProps('visited.color')};
  }

  &&&.kl-components-link_disabled {
    color: ${fromProps('disabled.color')};
      
    outline: none;
    cursor: default;
  }
  
  & > :not(:first-child) {
    margin-left: ${SPACES[2]}px;
  }
`;

export { IconWrapper, StyledLink, TextWrapper };
